17: package leaderelection
18: 
19: import (
20: 	"fmt"
21: 	"time"
22: 
23: 	"github.com/blang/semver/v4"
24: 	v1 "k8s.io/api/coordination/v1"
25: 	v1beta1 "k8s.io/api/coordination/v1beta1"
