29: func pickBestLeaderOldestEmulationVersion(candidates []*v1beta1.LeaseCandidate) *v1beta1.LeaseCandidate {
30: 	var electee *v1beta1.LeaseCandidate
31: 	for _, c := range candidates {
32: 		if !validLeaseCandidateForOldestEmulationVersion(c) {
33: 			continue
34: 		}
35: 		if electee == nil || compare(electee, c) > 0 {
36: 			electee = c
37: 		}
38: 	}
39: 	return electee
40: }
41: 
42: func pickBestStrategy(candidates []*v1beta1.LeaseCandidate) (v1.CoordinatedLeaseStrategy, error) {
43: 	nilStrategy := v1.CoordinatedLeaseStrategy("")
44: 	if len(candidates) == 0 {
45: 		return nilStrategy, fmt.Errorf("no candidates")
46: 	}
47: 	candidateName := candidates[0].Name
48: 	strategy := candidates[0].Spec.Strategy
49: 	highestBV := getBinaryVersionOrZero(candidates[0])
50: 
51: 	for _, c := range candidates[1:] {
52: 		binVersion := getBinaryVersionOrZero(c)
53: 		result := highestBV.Compare(binVersion)
54: 		if result < 0 {
55: 			strategy = c.Spec.Strategy
56: 			highestBV = binVersion
57: 			candidateName = c.Name
58: 		} else if result == 0 && c.Spec.Strategy != strategy {
59: 			return nilStrategy, fmt.Errorf("candidates %q, %q at same binary version but received differing strategies %s, %s", candidateName, c.Name, strategy, c.Spec.Strategy)
60: 		}
61: 	}
62: 	return strategy, nil
63: }
64: 
65: func validLeaseCandidateForOldestEmulationVersion(l *v1beta1.LeaseCandidate) bool {
66: 	_, err := semver.ParseTolerant(l.Spec.EmulationVersion)
67: 	if err != nil {
68: 		return false
69: 	}
70: 	_, err = semver.ParseTolerant(l.Spec.BinaryVersion)
71: 	return err == nil
72: }
73: 
74: func getEmulationVersionOrZero(l *v1beta1.LeaseCandidate) semver.Version {
75: 	value := l.Spec.EmulationVersion
76: 	v, err := semver.ParseTolerant(value)
77: 	if err != nil {
78: 		return semver.Version{}
79: 	}
80: 	return v
81: }
82: 
83: func getBinaryVersionOrZero(l *v1beta1.LeaseCandidate) semver.Version {
84: 	value := l.Spec.BinaryVersion
85: 	v, err := semver.ParseTolerant(value)
86: 	if err != nil {
87: 		return semver.Version{}
88: 	}
89: 	return v
90: }
91: 
92: // -1: lhs better, 1: rhs better
93: func compare(lhs, rhs *v1beta1.LeaseCandidate) int {
94: 	l := getEmulationVersionOrZero(lhs)
95: 	r := getEmulationVersionOrZero(rhs)
96: 	result := l.Compare(r)
97: 	if result == 0 {
98: 		l := getBinaryVersionOrZero(lhs)
99: 		r := getBinaryVersionOrZero(rhs)
100: 		result = l.Compare(r)
101: 	}
102: 	if result == 0 {
103: 		if lhs.CreationTimestamp.After(rhs.CreationTimestamp.Time) {
104: 			return 1
105: 		}
106: 		return -1
107: 	}
108: 	return result
109: }
